import { Link } from "react-router-dom";
import { goToNewsletter } from "../lib/goToNewsletter.js";
import { useDocumentHead } from "../lib/useDocumentHead.js";
import { useRouteScrollContext } from "../lib/useRouteScrollContext.js";
import StubSection from "./StubSection.jsx";
import { SEO } from "../data/seo.js";
import { HERO } from "../data/hero.js";
import { LINKS } from "../data/links.js";
import { SERVICES } from "../data/services.js";
import { TESTIMONIALS } from "../data/testimonials.js";
import { LOGO_INDUSTRIES } from "../data/logoIndustries.js";
import { CTA_BANNER } from "../data/ctaBanner.js";

// Home STUB. Owns: #hero, #industries, #services, #testimonials, #cta and the
// two Home showpiece mounts [data-showpiece="hero"] (CSS/SVG, S10) +
// [data-showpiece="pipeline"] (CustomsIQ, S11). No motion — S03/S04 add the
// backbone; S06 composes the real Home. Content imports from src/data/* only.
export default function Home() {
  useDocumentHead(SEO["/"]);
  // Route-scoped trigger context (scar #9). S06 registers real triggers via
  // `add()`; the scopeRef wrapper below is a plain block (scar #2).
  const { scopeRef } = useRouteScrollContext();

  return (
    <div ref={scopeRef}>
      <section
        id="hero"
        className="relative border-b border-line"
        style={{ paddingBlock: "var(--k-section-pad)" }}
      >
        <div className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)]">
          <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
            {HERO.tagline}
          </p>
          <h1 className="mt-5 max-w-4xl font-display text-[clamp(3.25rem,8.5vw,7.5rem)] font-bold leading-[0.95] tracking-[-0.02em] text-ink">
            {HERO.headline.join(" ")}
          </h1>
          <p className="mt-6 max-w-2xl font-body text-[clamp(1.0625rem,1.4vw,1.25rem)] leading-[1.6] text-ink-dim">
            {HERO.subtitle}
          </p>
          <div className="mt-8 flex flex-wrap gap-4">
            <a
              href={LINKS.calendly}
              target="_blank"
              rel="noopener noreferrer"
              className="rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
            >
              Book a call
            </a>
            <Link
              to="/work"
              className="rounded-sm border border-line-2 px-5 py-3 font-body text-sm font-medium text-ink transition-colors hover:border-accent"
            >
              See our work
            </Link>
          </div>
          <dl className="mt-12 grid gap-6 sm:grid-cols-3">
            {HERO.trustBar.map((t) => (
              <div key={t.label} className="border-t border-line pt-4">
                <dt className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
                  {t.label}
                </dt>
                <dd className="mt-1 font-body text-ink">{t.value}</dd>
              </div>
            ))}
          </dl>
          {/* H1 idle object — CSS/SVG slot (DIRECTION: no WebGL). S10 fills. */}
          <div
            data-showpiece="hero"
            className="mt-10 flex min-h-[180px] items-center justify-center rounded-md border border-dashed border-line-2 text-mono-label uppercase tracking-[0.12em] text-muted"
          >
            [hero] CSS/SVG polyhedron slot — filled by a later sprint
          </div>
        </div>
      </section>

      {/* H2 ★ CustomsIQ pipeline showpiece mount (S11 fills). */}
      <StubSection
        id="pipeline"
        eyebrow="The agent at work"
        title="Read · Ground · Reason · Classify · Cite"
        mount="pipeline"
      >
        <p className="max-w-2xl font-body text-ink-dim">
          A customs classification agent that shows its reasoning end to end —
          assembled stage by stage as you scroll. Filled in a later sprint.
        </p>
      </StubSection>

      {/* H3 industries marquee (8). */}
      <StubSection id="industries" eyebrow="Where it ships" title="Built for industries that haven't changed">
        <ul className="flex flex-wrap gap-3">
          {LOGO_INDUSTRIES.map((name) => (
            <li
              key={name}
              className="rounded-sm border border-line px-3 py-1 font-mono text-mono-trace text-ink-dim"
            >
              {name}
            </li>
          ))}
        </ul>
      </StubSection>

      {/* H4 services (3). */}
      <StubSection id="services" eyebrow="What we build" title="Two modes. One team.">
        <div className="grid gap-6 md:grid-cols-3">
          {SERVICES.map((s) => (
            <article key={s.title} className="rounded-md border border-line bg-surface p-6">
              <h3 className="font-display text-title font-semibold text-ink">{s.title}</h3>
              <p className="mt-3 font-body text-small text-ink-dim">{s.description}</p>
            </article>
          ))}
        </div>
      </StubSection>

      {/* H5 testimonials (3). */}
      <StubSection id="testimonials" eyebrow="Testimonials" title="What they told us">
        <div className="grid gap-6 md:grid-cols-3">
          {TESTIMONIALS.map((t) => (
            <figure key={t.role} className="rounded-md border border-line bg-surface p-6">
              <blockquote className="font-body text-ink">"{t.quote}"</blockquote>
              <figcaption className="mt-4 font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
                {t.role}
              </figcaption>
            </figure>
          ))}
        </div>
      </StubSection>

      {/* H6 CTA banner — reaches #newsletter in the footer (cross-section anchor). */}
      <StubSection id="cta" eyebrow="Next step" title={CTA_BANNER.headline}>
        <p className="max-w-2xl font-body text-ink-dim">{CTA_BANNER.subtitle}</p>
        <div className="mt-6 flex flex-wrap gap-4">
          {/* Locked behavior: the CTA reaches the footer #newsletter via the
              S05 shared helper (Lenis-aware, reduced-motion instant). */}
          <a
            href="#newsletter"
            onClick={(e) => {
              e.preventDefault();
              goToNewsletter();
            }}
            className="rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
          >
            {CTA_BANNER.button}
          </a>
          <a
            href={LINKS.calendly}
            target="_blank"
            rel="noopener noreferrer"
            className="rounded-sm border border-line-2 px-5 py-3 font-body text-sm font-medium text-ink transition-colors hover:border-accent"
          >
            Book a call
          </a>
        </div>
        <ul className="mt-6 flex flex-wrap gap-3">
          {CTA_BANNER.badges.map((b) => (
            <li key={b} className="font-mono text-mono-trace text-muted">
              {b}
            </li>
          ))}
        </ul>
      </StubSection>
    </div>
  );
}

