1	// Shared route manifest + helpers for the QA harness.
2	//
3	// This is the single source of truth every QA script crawls. The current site
4	// is a single page ("/"); Sprint 02 splits it into a real router and MUST keep
5	// this array in sync with the router (one ROUTES entry per navigable path).
6	//
7	// Each route:
8	//   path         URL path to visit (joined onto DEV_URL)
9	//   name         filesystem-safe tag for screenshot folders
10	//   ownedIds     section ids this route is expected to render (used by future
11	//                route-aware checks; empty allowed)
12	//   showpiece    CSS selector of a GL/scrub showpiece on the route, or null.
13	//                walkthrough/verify measure draw calls only where this is set.
14	//   mobileStatic true => mobile/reduced-motion must render a designed static
15	//                final state (never blank), per scar #8.
16	//   legacy       true ONLY for the pre-rebuild site: axe a11y/contrast audit is
17	//                logged informationally instead of gating. Rebuilt routes
18	//                (Sprint 02 onward) must NOT carry this flag — they gate hard
19	//                on serious/critical axe violations incl. color-contrast.
20	import fs from "fs";
21	import path from "path";
22	import { fileURLToPath } from "url";
23	
24	export const DEV_URL = "http://localhost:5173";
25	
26	// Real 4-route IA (plans/design/DIRECTION.md §IA), locked by S02. Mirrors the
27	// router in src/App.jsx and the CONTRACTS Route map. Section ids are the stub-
28	// owned anchors each page renders this sprint; page sprints (S06–S09) keep them
29	// in sync as they compose the real sections. `#newsletter` lives in the footer
30	// and resolves from every route (the CTA banner targets it), so it is not listed
31	// per-route here.
32	//
33	// Showpiece selectors are the LOCKED mount-point NAMES (data-showpiece="hero" /
34	// "pipeline" / "skyline"). They are filled by the GL sprints (S10/S11/S12).
35	// IMPORTANT (S02): the stubs carry ZERO GL on every route — the hero is CSS/SVG
36	// and the pipeline/skyline mounts are empty placeholder boxes with no canvas and
37	// no window.__gl. So `showpiece` is null on every route NOW, which makes verify
38	// assert "no GL chunks fetched" on all four routes (the truthful, stronger check
39	// for stubs). S10/S11/S12 repoint these to the real GL selectors when WebGL lands;
40	// at that point a non-null showpiece means "GL bytes allowed on desktop here".
41	//
42	// `expect` carries the per-route INTEGRATION expectations verify.mjs gates on.
43	// Splitting the single page into 4 routes made the facts contract route-aware:
44	// the 18 team LinkedIn links live only on /studio, the EmailJS form only on
45	// /contact, while the footer integrations (Sender #newsletter mount, company
46	// LinkedIn, mailto) and a Calendly CTA render on EVERY route via the global
47	// nav+footer. facts_check.mjs still asserts the FULL contract site-wide.
48	const FOOTER = { senderMount: true, companyLinked: true, mailto: true };
49	
50	export const ROUTES = [
51	  {
52	    path: "/",
53	    name: "home",
54	    ownedIds: ["hero", "pipeline", "industries", "services", "testimonials", "cta"],
55	    showpiece: null,
56	    mobileStatic: true,
57	    legacy: false,
58	    expect: { calendlyMin: 3, team: false, contactForm: false, ...FOOTER },
59	  },
60	  {
61	    path: "/work",
62	    name: "work",
63	    ownedIds: ["case-studies", "industries", "recap"],
64	    showpiece: null,
65	    mobileStatic: true,
66	    legacy: false,
67	    expect: { calendlyMin: 3, team: false, contactForm: false, ...FOOTER },
68	  },
69	  {
70	    path: "/studio",
71	    name: "studio",
72	    ownedIds: ["process", "team", "manifesto"],
73	    showpiece: null,
74	    mobileStatic: true,
75	    legacy: false,
76	    // The 18 team LinkedIn member links live here.
77	    expect: { calendlyMin: 3, team: true, contactForm: false, ...FOOTER },
78	  },
79	  {
80	    path: "/contact",
81	    name: "contact",
82	    ownedIds: ["contact"],
83	    showpiece: null,
84	    mobileStatic: true,
85	    legacy: false,
86	    // The EmailJS form (4 fields, locked ids) lives here.
87	    expect: { calendlyMin: 3, team: false, contactForm: true, ...FOOTER },
88	  },
89	];
90	
91	// /tmp/shots/<tag>/  — walkthrough signature shots.
92	// /tmp/shots-dense/<route-name>/ — dense scroll shots.
93	export function SHOTS_DIR(tag = "manual") {
94	  return path.join("/tmp/shots", tag);
95	}
96	export function DENSE_DIR(routeName) {
97	  return path.join("/tmp/shots-dense", routeName);
98	}
99	
100	export function routeUrl(route, query = "") {
101	  const base = DEV_URL + route.path;
102	  if (!query) return base;
103	  return base + (route.path.includes("?") ? "&" : "?") + query.replace(/^\?/, "");
104	}
105	
106	// Robust Chromium/Chrome resolver. Order:
107	//   1. $CHROME_PATH (explicit override)
108	//   2. playwright-core's bundled chromium.executablePath() if it resolves
109	//   3. common macOS install paths (Chrome for Testing, then Google Chrome)
110	// Exits with a clear, actionable message if none is found.
111	export async function resolveChrome() {
112	  const fromEnv = process.env.CHROME_PATH;
113	  if (fromEnv && fs.existsSync(fromEnv)) return fromEnv;
114	
115	  try {
116	    const { chromium } = await import("playwright-core");
117	    const p = chromium.executablePath();
118	    if (p && fs.existsSync(p)) return p;
119	  } catch {
120	    // playwright-core absent or no browser downloaded — fall through to paths.
121	  }
122	
123	  const candidates = [
124	    "/Applications/Google Chrome for Testing.app/Contents/MacOS/Google Chrome for Testing",
125	    `${process.env.HOME || ""}/Applications/Google Chrome for Testing.app/Contents/MacOS/Google Chrome for Testing`,
126	    "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
127	    "/Applications/Chromium.app/Contents/MacOS/Chromium",
128	    "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
129	  ];
130	  for (const c of candidates) {
131	    if (c && fs.existsSync(c)) return c;
132	  }
133	
134	  console.error(
135	    [
136	      "FATAL: no Chromium/Chrome executable found.",
137	      "Tried, in order:",
138	      "  1. $CHROME_PATH (env override)",
139	      "  2. playwright-core chromium.executablePath()",
140	      "  3. common macOS install paths",
141	      "",
142	      "Fix one of:",
143	      "  - export CHROME_PATH=/path/to/chrome",
144	      "  - npx playwright install chromium   (downloads the bundled build)",
145	      "  - install Google Chrome",
146	    ].join("\n")
147	  );
148	  process.exit(2);
149	}
150	
151	// Tiny arg parser: --tag=foo --route=/ ?skippreload-style flags.
152	export function parseArgs(argv = process.argv.slice(2)) {
153	  const out = { _: [] };
154	  for (const a of argv) {
155	    const m = a.match(/^--([^=]+)(?:=(.*))?$/);
156	    if (m) out[m[1]] = m[2] === undefined ? true : m[2];
157	    else out._.push(a);
158	  }
159	  return out;
160	}
161	
162	// Resolve the cwd's repo root (two levels up from scripts/qa/).
163	export function repoRoot() {
164	  const here = path.dirname(fileURLToPath(import.meta.url));
165	  return path.resolve(here, "..", "..");
166	}
