/**
 * KineticMarquee — velocity-coupled marquee (DIRECTION "KineticMarquee").
 * THE single consumer of scrollBus this sprint.
 *
 * A whitespace-nowrap track holds the item row TWICE (second copy aria-hidden)
 * and drifts left at `speed` px/s, plus |scrollBus.velocity|*velocityFactor of
 * extra drift in the SAME direction as the scroll sign — deterministic, base
 * drift never reverses. Offset wraps modulo the single-copy row width (cached
 * on mount + debounced resize, never per frame) and is written via one
 * quickSetter x. A root ScrollTrigger (onToggle) flips an `active` flag so the
 * ticker only writes while on-screen (it does NOT kill anything in onToggle).
 *
 * Props:
 *   items           string[]  (required) the marquee tokens.
 *   speed           number    40    base leftward drift, px/s.
 *   velocityFactor  number    0.1   extra drift per px/s of scroll velocity.
 *   skewOnVelocity  boolean   false the ONE allowed velocity-skew (default OFF).
 *   className       string    ""    passthrough to the root.
 *   renderItem      fn        —     optional item=>node (else the chip idiom).
 *
 * Chip idiom (default renderItem): rounded-sm border border-line px-3 py-1
 * font-mono text-[0.8125rem] text-ink-dim.
 *
 * Gate (scar #8): useMotionStatic() ⇒ a flex-wrap list of the items (each chip
 * fully visible, no duplication, no overflow, no horizontal motion),
 * data-static="true", zero GSAP / zero scrollBus subscription.
 *
 * Reduced/mobile fallback: the static flex-wrap list above (fully readable).
 *
 * Scars: #1 — onToggle only flips a boolean, never kills (no synchronous kill).
 * #4 — the root hosts no absolute inset-0 child; still marked relative for the
 * overflow-hidden frame. #5 n/a (not a scrubbed scene — a continuous drift; no
 * half-scrubbed state to strand). #7 — one gsap.ticker callback, zero per-frame
 * allocations (mutates `offset`, reads cached rowWidth + scrollBus.velocity,
 * no getBoundingClientRect per frame, no setState in the loop). All GSAP inside
 * the component's own gsap.context; cleanup removes ticker, unsubscribes the
 * bus, removes the resize listener, reverts (StrictMode idempotent — subscribe/
 * unsubscribe pairs balance via scrollBus refcount).
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useMotionStatic } from "./useMotionStatic.js";
import { scrollBus, subscribeScrollBus } from "../../lib/scrollBus.js";

gsap.registerPlugin(ScrollTrigger);

function defaultChip(item) {
  return (
    <span className="rounded-sm border border-line px-3 py-1 font-mono text-[0.8125rem] text-ink-dim">
      {item}
    </span>
  );
}

function clamp(n, lo, hi) {
  return n < lo ? lo : n > hi ? hi : n;
}

function KineticMarquee({
  items,
  speed = 40,
  velocityFactor = 0.1,
  skewOnVelocity = false,
  className = "",
  renderItem,
}) {
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);
  const trackRef = useRef(null);
  const rowRef = useRef(null);

  const render = renderItem || defaultChip;

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    const track = trackRef.current;
    const row = rowRef.current;
    if (!root || !track || !row) return undefined;

    const ctx = gsap.context(() => {
      const unsubscribe = subscribeScrollBus();
      const setX = gsap.quickSetter(track, "x", "px");
      const setSkew = skewOnVelocity
        ? gsap.quickSetter(track, "skewX", "deg")
        : null;

      // Cached on mount + debounced resize — never measured per frame.
      let rowWidth = row.offsetWidth || 1;
      let offset = 0;
      let active = true;
      let resizeCall = null;

      const measure = () => {
        rowWidth = row.offsetWidth || 1;
      };
      const onResize = () => {
        if (resizeCall) resizeCall.kill();
        resizeCall = gsap.delayedCall(0.2, measure);
      };

      function tick(_time, deltaTime) {
        if (!active) return;
        const dt = Math.min(deltaTime, 64) / 1000;
        const v = scrollBus.velocity;
        const sign = v === 0 ? 1 : Math.sign(v);
        // Base drift always leftward; |velocity| adds extra in the scroll sign.
        const extra = Math.min(Math.abs(v), 4000) * velocityFactor * sign;
        offset -= (speed + extra) * dt;
        // Wrap into [-rowWidth, 0] so the second copy fills the seam.
        offset = ((offset % rowWidth) + rowWidth) % rowWidth - rowWidth;
        setX(offset);
        if (setSkew) setSkew(clamp(v * 0.003, -6, 6));
      }

      // onToggle only flips `active` (scar #1 — never kill here).
      const st = ScrollTrigger.create({
        trigger: root,
        start: "top bottom",
        end: "bottom top",
        onToggle: (self) => {
          active = self.isActive;
        },
      });
      active = st.isActive;

      window.addEventListener("resize", onResize);
      gsap.ticker.add(tick);

      return () => {
        gsap.ticker.remove(tick);
        window.removeEventListener("resize", onResize);
        if (resizeCall) resizeCall.kill();
        unsubscribe();
      };
    }, rootRef);

    return () => ctx.revert();
  }, [isStatic, speed, velocityFactor, skewOnVelocity]);

  const ariaLabel = Array.isArray(items) ? items.join(", ") : undefined;

  if (isStatic) {
    return (
      <div
        ref={rootRef}
        data-kinetic-marquee
        data-static="true"
        className={`flex flex-wrap gap-3 ${className}`.trim()}
      >
        {items.map((item, i) => (
          <span key={`${item}-${i}`}>{render(item)}</span>
        ))}
      </div>
    );
  }

  return (
    <div
      ref={rootRef}
      data-kinetic-marquee
      role="img"
      aria-label={ariaLabel}
      className={`relative overflow-hidden ${className}`.trim()}
    >
      <div
        ref={trackRef}
        className="inline-flex whitespace-nowrap will-change-transform"
        aria-hidden="true"
      >
        <div ref={rowRef} className="inline-flex shrink-0 gap-3 pr-3">
          {items.map((item, i) => (
            <span key={`a-${item}-${i}`}>{render(item)}</span>
          ))}
        </div>
        <div className="inline-flex shrink-0 gap-3 pr-3" aria-hidden="true">
          {items.map((item, i) => (
            <span key={`b-${item}-${i}`}>{render(item)}</span>
          ))}
        </div>
      </div>
    </div>
  );
}

export default KineticMarquee;
export { KineticMarquee };

