/**
 * SnapStack — cards arrive from the right and grid-lock into place (S04).
 *
 * On first scroll into view, each direct child slides in from the right with a
 * slight alternating rotation and snap-locks with the EASE.SNAP overshoot
 * (the "click into the grid" feel). Opacity fades separately on EASE.PRIMARY —
 * NEVER on SNAP (law 2: overshoot is transforms only). Reveals once, holds.
 *
 * The component does NOT impose a grid: the caller's `className` owns layout
 * (grid/flex). SnapStack only animates the direct children in place.
 *
 * Props:
 *   children   the cards (each direct child is one animated card).
 *   stagger    inter-card stagger seconds (default STAGGER.CELL * 2).
 *   start      ScrollTrigger start (default "top 78%").
 *   className  layout classes on the root (caller-owned grid/flex).
 *
 * Gate: scar #8 static — when useMotionStatic() is true children render plain
 * in the caller's layout, fully visible, data-static="true" and
 * data-revealed="true" (QA hook). No trigger, no transform.
 *
 * Scars: #2 one easing language — transforms EASE.SNAP, opacity EASE.PRIMARY,
 * split across two tweens so SNAP never touches opacity;
 * #12 initial hidden state is set INSIDE the same context that creates the
 *     trigger (a `once` trigger fires immediately if already in view);
 * #13 data-revealed="true" set via setAttribute in onComplete.
 *
 * Alias: `CardStack` re-exports SnapStack.
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { EASE, DUR, STAGGER, TRAVEL } from "../../lib/motion.js";
import { useMotionStatic } from "./useMotionStatic.js";

gsap.registerPlugin(ScrollTrigger);

function SnapStack({
  children,
  stagger = STAGGER.CELL * 2,
  start = "top 78%",
  className = "",
}) {
  const rootRef = useRef(null);
  const isStatic = useMotionStatic();

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    if (!root) return undefined;

    const ctx = gsap.context(() => {
      const cards = gsap.utils.toArray(":scope > *", root);
      if (cards.length === 0) return;

      // Scar #12 — hidden initial state committed in the SAME context as the
      // trigger. Alternating rotation per index (transforms get the overshoot).
      cards.forEach((card, i) => {
        gsap.set(card, {
          x: TRAVEL * 1.6,
          rotation: i % 2 ? 2.2 : -1.6,
          opacity: 0,
        });
      });

      const tl = gsap.timeline({
        scrollTrigger: { trigger: root, start, once: true },
        onComplete: () => root.setAttribute("data-revealed", "true"),
      });

      // Transforms snap-lock with EASE.SNAP (overshoot)…
      tl.to(
        cards,
        {
          x: 0,
          rotation: 0,
          duration: DUR.MD,
          ease: EASE.SNAP,
          stagger,
        },
        0
      );
      // …opacity rises on EASE.PRIMARY (NEVER SNAP on opacity).
      tl.to(
        cards,
        {
          opacity: 1,
          duration: DUR.MD,
          ease: EASE.PRIMARY,
          stagger,
        },
        0
      );
    }, root);

    return () => ctx.revert();
  }, [isStatic, stagger, start]);

  return (
    <div
      ref={rootRef}
      data-snap-stack=""
      data-static={isStatic ? "true" : undefined}
      data-revealed={isStatic ? "true" : undefined}
      className={className}
    >
      {children}
    </div>
  );
}

export default SnapStack;
export { SnapStack };
export const CardStack = SnapStack;

