1	/**
2	 * ParallaxLayer — counter-parallax layer (multi-directional doctrine, S04).
3	 *
4	 * Translates its children at a fraction of scroll speed across the element's
5	 * full viewport pass (start "top bottom" → end "bottom top"), so the layer
6	 * drifts relative to the page. Negative `speed` = counter-scroll (moves against
7	 * the page). Linear scrub (ease "none") — a parallax must track scroll 1:1.
8	 *
9	 * Travel note: total travel ≈ |speed| * 600px (fromTo +speed*300 → -speed*300).
10	 * For the default speed -0.15 that's ~90px — comfortably above TRAVEL (40), so
11	 * the drift reads as a deliberate move, not a glitch. Keep |speed| ≳ 0.07 to
12	 * stay perceptible.
13	 *
14	 * Props:
15	 *   speed     parallax factor (default -0.15; negative = counter-scroll).
16	 *   axis      "y" (default) or "x" — which axis drifts.
17	 *   trigger   "self" (default — the layer's own pass) or "parent" (the parent
18	 *             element's pass; resolved as root.parentElement in the effect).
19	 *   className extra classes on the root.
20	 *   children  the parallaxed content.
21	 *   as        root element tag (default "div").
22	 *
23	 * Gate: scar #8 static — when useMotionStatic() is true children render plain
24	 * with no transform, data-static="true". Reduced/mobile users see a still
25	 * layer in its resting position.
26	 *
27	 * Scars: #7 (single scrubbed tween; no per-frame work in JS),
28	 * #8 (static = no transform).
29	 */
30	import { createElement, useLayoutEffect, useRef } from "react";
31	import { gsap } from "gsap";
32	import { ScrollTrigger } from "gsap/ScrollTrigger";
33	import { useMotionStatic } from "./useMotionStatic.js";
34	
35	gsap.registerPlugin(ScrollTrigger);
36	
37	function ParallaxLayer({
38	  speed = -0.15,
39	  axis = "y",
40	  trigger = "self",
41	  className = "",
42	  children,
43	  as = "div",
44	}) {
45	  const rootRef = useRef(null);
46	  const isStatic = useMotionStatic();
47	
48	  useLayoutEffect(() => {
49	    if (isStatic) return undefined;
50	    const root = rootRef.current;
