1	// verify.mjs — route-driven assertion suite (v0).
2	//
3	// Boots playwright-core against the running dev server (:5173) and asserts the
4	// invariants that must hold on every build. v0 targets the CURRENT single-page
5	// site; sprints extend ROUTES + add route-aware checks via the check() harness.
6	//
7	// Usage:
8	//   node scripts/qa/verify.mjs               full suite, all ROUTES
9	//   node scripts/qa/verify.mjs --route=/     restrict to one route
10	//   node scripts/qa/verify.mjs --skippreload pass ?skippreload to every load
11	//
12	// Exit 0 only if every check passes; non-zero with a failure list otherwise.
13	import fs from "fs";
14	import { chromium } from "playwright-core";
15	import { ROUTES, DEV_URL, resolveChrome, parseArgs } from "./routes.mjs";
16	
17	// axe-core source, injected per page for the a11y/contrast audit (WCAG 2 A+AA).
18	const AXE_SOURCE = fs.readFileSync(
19	  new URL("../../node_modules/axe-core/axe.min.js", import.meta.url),
20	  "utf8"
21	);
22	
23	const args = parseArgs();
24	const SKIP = args.skippreload ? "skippreload" : "";
25	const onlyRoute = args.route || null;
26	
27	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
28	
29	// ---- check() harness -------------------------------------------------------
30	const results = [];
31	function check(name, ok, info = "") {
32	  results.push({ name, ok: !!ok, info });
33	  console.log(`${ok ? "PASS" : "FAIL"} ${name}${info ? `  ${info}` : ""}`);
34	}
35	
36	// Any of these fetched while reduced-motion / mobile / a no-GL route is active
37	// is a chunk-gating leak (scar #10 + perf budget). Matches Vite dep-optimized
38	// paths and any future manual GL chunk names.
39	const GL_CHUNKS =
40	  /node_modules\/\.vite\/deps\/(three|@react-three|postprocessing)|node_modules\/(three|@react-three|postprocessing)|\b(three|drei|HeroCanvas|GLStage|webgl|PipelineScene|[A-Za-z]*Scene)[-.][\w]+\.js/i;
41	
42	// Draw-call measurement: composer passes are only counted with autoReset off,
43	// accumulated across ~10 ticks then averaged (autoReset-on reports just the
44	// final screen-quad pass == 1). Returns -1 when no GL context (window.__gl).
45	async function measureDrawCalls(page) {
46	  return page.evaluate(
47	    () =>
48	      new Promise((res) => {
49	        const gl = window.__gl;
50	        if (!gl) return res(-1);
51	        gl.info.autoReset = false;
52	        gl.info.reset();
53	        if (window.__frame) window.__frame.needsFrames = 30;
54	        let ticks = 0;
55	        const tick = () => {
56	          if (++ticks < 10) return requestAnimationFrame(tick);
57	          const avg = Math.round(gl.info.render.calls / ticks);
58	          gl.info.autoReset = true;
59	          res(avg);
60	        };
61	        requestAnimationFrame(tick);
62	      })
63	  );
64	}
65	
66	// ScrollTrigger count, or -1 when the page hasn't exposed window.__stCount yet
67	// (current site does not). Callers skip gracefully on -1.
68	function stCount(page) {
69	  return page.evaluate(() => (window.__stCount ? window.__stCount() : -1));
70	}
71	
72	const EXEC = await resolveChrome();
73	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
74	
75	const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
76	// "/lab" is not a ROUTES entry (dev-only bench) — --route=/lab runs just the
77	// S04 lab suite below.
78	if (routes.length === 0 && onlyRoute !== "/lab") {
79	  console.error(`No ROUTES match --route=${onlyRoute}`);
80	  process.exit(2);
81	}
82	
83	for (const route of routes) {
84	  const url = DEV_URL + route.path + (SKIP ? (route.path.includes("?") ? "&" : "?") + SKIP : "");
85	
86	  // ---- DESKTOP pass: load clean, audit links/integrations, GL on showpiece --
87	  {
88	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
89	    const consoleErrors = [];
90	    const pageErrors = [];
91	    const requests = [];
92	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
93	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
94	    page.on("request", (r) => requests.push(r.url()));
95	
96	    let emailjsReq = null;
97	    await page.route("**/api.emailjs.com/**", (r) => {
98	      const req = r.request();
99	      // Keep the FULL post body — service/template ids live deep inside the
100	      // multipart form-data, well past any fixed slice. Slice only for display.
101	      emailjsReq = { url: req.url(), method: req.method(), post: req.postData() || "" };
102	      r.fulfill({ status: 200, body: "OK" });
103	    });
104	
105	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
106	    await sleep(3500);
107	
108	    const tag = `[${route.name}]`;
109	
110	    // Route mounts its OWN stub (not the catch-all NotFound, not another page).
111	    // Asserted by the route's owned section ids being present AND the 404 marker
112	    // being absent. This is the per-route mount + deep-reload SPA-fallback proof:
113	    // we navigated directly to `url` (e.g. /work) and the real route mounted.
114	    const mount = await page.evaluate((ids) => ({
115	      ownedPresent: ids.filter((id) => !!document.getElementById(id)).length,
116	      ownedTotal: ids.length,
117	      isNotFound: !!document.getElementById("not-found"),
118	    }), route.ownedIds || []);
119	    check(
120	      `${tag} route mounts own stub (deep-reload SPA fallback)`,
121	      mount.ownedTotal > 0 && mount.ownedPresent === mount.ownedTotal && !mount.isNotFound,
122	      `(${mount.ownedPresent}/${mount.ownedTotal} owned ids, notFound=${mount.isNotFound})`
123	    );
124	
125	    // Nav links present.
126	    const navCount = await page.evaluate(
127	      () => document.querySelectorAll("nav a, nav button").length
128	    );
129	    check(`${tag} nav links present`, navCount >= 5, `(${navCount})`);
130	
131	    // Link / integration audit.
132	    const links = await page.evaluate(() => ({
133	      linkedinMembers: document.querySelectorAll('a[href*="linkedin.com/in/"]').length,
134	      linkedinCompany: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
135	      calendly: document.querySelectorAll('a[href*="calendly.com/sachmeet-kartar/30min"]').length,
136	      mailto: document.querySelectorAll('a[href="mailto:hello@kartar.ai"]').length,
137	      sender:
138	        !!document.querySelector('[data-sender-form-id]') ||
139	        !!document.querySelector('#sender-form'),
140	      fields: {
141	        from_name: !!document.querySelector('[name="from_name"]'),
142	        from_email: !!document.querySelector('[name="from_email"]'),
143	        from_phone: !!document.querySelector('[name="from_phone"]'),
144	        message: !!document.querySelector('[name="message"]'),
145	      },
146	    }));
147	    // Per-route INTEGRATION expectations (route.expect, from routes.mjs). The
148	    // single page is now split across 4 routes, so the contract is route-aware:
149	    // the 18 team LinkedIn links live only on the `team` route; the EmailJS form
150	    // only on the `contactForm` route; footer integrations + a Calendly CTA on
151	    // every route. facts_check.mjs still asserts the FULL contract site-wide.
152	    const exp = route.expect || {};
153	    if (exp.team) {
154	      check(`${tag} 18 LinkedIn member links`, links.linkedinMembers === 18, `(${links.linkedinMembers})`);
155	    }
156	    if (exp.companyLinked) {
157	      check(`${tag} >=1 company LinkedIn`, links.linkedinCompany >= 1, `(${links.linkedinCompany})`);
158	    }
159	    const calMin = exp.calendlyMin ?? 3;
160	    check(`${tag} >=${calMin} Calendly links`, links.calendly >= calMin, `(${links.calendly})`);
161	    if (exp.mailto) {
162	      check(`${tag} mailto hello@kartar.ai`, links.mailto >= 1);
163	    }
164	    if (exp.senderMount) {
165	      check(`${tag} Sender form mount present`, links.sender);
166	    }
167	    if (exp.contactForm) {
168	      check(
169	        `${tag} EmailJS fields present`,
170	        links.fields.from_name && links.fields.from_email && links.fields.from_phone && links.fields.message,
171	        `(name=${links.fields.from_name} email=${links.fields.from_email} phone=${links.fields.from_phone} msg=${links.fields.message})`
172	      );
173	    }
174	
175	    // EmailJS stub-submit: fill + submit, assert the request is formed with the
176	    // right service/template ids and the success text appears. Never sent — the
177	    // api.emailjs.com route is intercepted and fulfilled with OK.
178	    const hasContact = await page.evaluate(() => !!document.querySelector('form [name="from_name"]'));
179	    if (hasContact) {
180	      await page.evaluate(() => {
181	        const el = document.querySelector('form [name="from_name"]')?.closest("section") || document.querySelector("#contact");
182	        if (!el) return;
183	        const top = el.getBoundingClientRect().top + (window.__lenis ? window.__lenis.scroll : window.scrollY);
184	        if (window.__lenis) window.__lenis.scrollTo(top, { immediate: true });
185	        else window.scrollTo(0, top);
186	      });
187	      await sleep(1000);
188	      await page.fill('[name="from_name"]', "Verification Bot");
189	      await page.fill('[name="from_email"]', "verify@example.com");
190	      await page.fill('[name="from_phone"]', "+91 00000 00000");
191	      await page.fill('[name="message"]', "Automated verification - not a real enquiry.");
192	      await page.click('form button[type="submit"]');
193	      await sleep(2500);
194	
195	      check(
196	        `${tag} EmailJS request formed (stubbed)`,
197	        !!emailjsReq,
198	        emailjsReq ? `→ ${emailjsReq.method} ${emailjsReq.url.slice(0, 50)}` : ""
199	      );
200	      const post = emailjsReq?.post || "";
201	      check(
202	        `${tag} EmailJS service_gtn59h8 in request`,
203	        post.includes("service_gtn59h8"),
204	        post ? "" : "(no post body captured)"
205	      );
206	      check(
207	        `${tag} EmailJS template_2l3bp6f in request`,
208	        post.includes("template_2l3bp6f"),
209	        post ? "" : "(no post body captured)"
210	      );
211	      const success = await page.evaluate(() =>
212	        document.body.innerText.includes("Message sent. We'll get back to you within 24 hours.")
213	      );
214	      check(`${tag} success message shown`, success);
215	    }
216	
217	    // GL chunk-gating on desktop: a route with NO showpiece must never fetch GL
218	    // chunks. (A showpiece route legitimately may — checked only on reduced/mobile.)
219	    if (!route.showpiece) {
220	      const leaked = requests.filter((u) => GL_CHUNKS.test(u));
221	      check(`${tag} no GL chunks on no-showpiece route (desktop)`, leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
222	    } else {
223	      const calls = await measureDrawCalls(page);
224	      // -1 => no __gl yet; treat as informational pass (showpiece may predate
225	      // the GL-info hook). Once present, enforce the <=40 budget.
226	      check(
227	        `${tag} draw calls <= 40 (showpiece)`,
228	        calls === -1 || (calls > 0 && calls <= 40),
229	        `(${calls === -1 ? "no __gl hook yet" : calls})`
230	      );
231	    }
232	
233	    // __stCount nav-leak baseline — only meaningful once exposed; skip otherwise.
234	    const st = await stCount(page);
235	    if (st >= 0) check(`${tag} ScrollTrigger count > 0`, st > 0, `(${st})`);
236	
237	    // S03 backbone globals: Lenis instance + trigger counter (desktop is the
238	    // non-reduced, non-mobile tier, so Lenis MUST exist here).
239	    const backbone = await page.evaluate(() => ({
240	      lenis: !!(window.__lenis && typeof window.__lenis.scrollTo === "function"),
241	      stCountFn: typeof window.__stCount === "function",
242	      preloaderDone: window.__preloaderDone === true,
243	    }));
244	    check(`${tag} window.__lenis exposed (has scrollTo)`, backbone.lenis);
245	    check(`${tag} window.__stCount is a function`, backbone.stCountFn);
246	    check(`${tag} preloaderDone fired`, backbone.preloaderDone);
247	
248	    // ---- S05 chrome suite: navbar/footer/cursor/seam/newsletter ------------
249	    const chrome = await page.evaluate(() => {
250	      const hrefs = ["/", "/work", "/studio", "/contact"];
251	      const seam = document.querySelector("[data-route-seam]");
252	      const seamStyle = seam ? getComputedStyle(seam) : null;
253	      return {
254	        headerLinks: hrefs.filter((h) => !!document.querySelector(`header nav a[href="${h}"]`)).length,
255	        footerLinks: hrefs.filter((h) => !!document.querySelector(`footer a[href="${h}"]`)).length,
256	        cursor: !!document.querySelector("[data-magnetic-cursor]"),
257	        senderContainers: document.querySelectorAll("[data-sender-form-id]").length,
258	        companyLinks: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
259	        newsletterInFooter: !!document.querySelector("footer #newsletter"),
260	        seam: !!seam,
261	        seamTransform: seamStyle ? seamStyle.transform : "missing",
262	        seamOverflowY: seamStyle ? seamStyle.overflowY : "missing",
263	      };
264	    });
265	    check(`${tag} navbar renders all 4 NAV route links`, chrome.headerLinks === 4, `(${chrome.headerLinks}/4)`);
266	    check(`${tag} footer renders all 4 NAV route links (one NAV source)`, chrome.footerLinks === 4, `(${chrome.footerLinks}/4)`);
267	    check(`${tag} custom cursor active (desktop fine pointer)`, chrome.cursor);
268	    check(`${tag} exactly ONE Sender container (StrictMode-safe)`, chrome.senderContainers === 1, `(${chrome.senderContainers})`);
269	    check(`${tag} exactly ONE company LinkedIn link`, chrome.companyLinks === 1, `(${chrome.companyLinks})`);
270	    check(`${tag} #newsletter lives in the footer`, chrome.newsletterInFooter);
271	    check(
272	      `${tag} seam is not a scroll container (scar #2)`,
273	      chrome.seam && chrome.seamTransform === "none" && chrome.seamOverflowY === "visible",
274	      `(transform=${chrome.seamTransform} overflowY=${chrome.seamOverflowY})`
275	    );
276	
277	    // Real window still scrolls THROUGH the seam (no nested scroller).
278	    const winScrollY = await page.evaluate(async () => {
279	      if (window.__lenis) window.__lenis.scrollTo(600, { immediate: true });
280	      else window.scrollTo(0, 600);
281	      await new Promise((r) => setTimeout(r, 400));
282	      return window.scrollY;
283	    });
284	    check(`${tag} real window scrolls through the seam (scar #2)`, winScrollY > 300, `(scrollY=${winScrollY})`);
285	
286	    // Locked CTA→newsletter behavior via the shared helper (dev-only global).
287	    const reach = await page.evaluate(async () => {
288	      if (typeof window.__goToNewsletter !== "function") return { ok: false, why: "helper global missing" };
289	      const issued = window.__goToNewsletter();
290	      await new Promise((r) => setTimeout(r, 1800));
291	      const el = document.getElementById("newsletter");
292	      if (!el) return { ok: false, why: "no #newsletter" };
293	      const rect = el.getBoundingClientRect();
294	      return {
295	        ok: issued && rect.top < window.innerHeight && rect.bottom > 0,
296	        why: `top=${Math.round(rect.top)}`,
297	      };
298	    });
299	    check(`${tag} goToNewsletter lands viewport on #newsletter`, reach.ok, `(${reach.why})`);
300	
301	    check(`${tag} zero console errors`, consoleErrors.length === 0, consoleErrors[0] || "");
302	    check(`${tag} zero page errors`, pageErrors.length === 0, pageErrors[0] || "");
303	
304	    // ---- AXE a11y + contrast audit (WCAG 2 A+AA) ---------------------------
305	    // Readability/contrast is part of the gate, not a vibe: serious+critical
306	    // violations (color-contrast is "serious") fail rebuilt routes. The legacy
307	    // pre-rebuild route only logs, so the chain can't deadlock on old UI debt.
308	    try {
309	      await page.addScriptTag({ content: AXE_SOURCE });
310	      const axe = await page.evaluate(async () => {
311	        const res = await window.axe.run(document, {
312	          runOnly: { type: "tag", values: ["wcag2a", "wcag2aa"] },
313	          resultTypes: ["violations"],
314	        });
315	        return res.violations.map((v) => ({
316	          id: v.id, impact: v.impact, nodes: v.nodes.length, help: v.help,
317	        }));
318	      });
319	      const blocking = axe.filter((v) => v.impact === "critical" || v.impact === "serious");
320	      if (route.legacy) {
321	        check(
322	          `${tag} axe audit (legacy: informational)`,
323	          true,
324	          `(${blocking.length} serious+critical${blocking.length ? `: ${blocking.map((v) => v.id).join(", ").slice(0, 90)}` : ""})`
325	        );
326	      } else {
327	        check(
328	          `${tag} axe: no serious/critical violations`,
329	          blocking.length === 0,
330	          blocking[0] ? `${blocking[0].id} x${blocking[0].nodes} — ${blocking[0].help}`.slice(0, 120) : ""
331	        );
332	        const contrast = axe.find((v) => v.id === "color-contrast");
333	        check(`${tag} axe: text contrast (WCAG AA)`, !contrast, contrast ? `x${contrast.nodes} nodes failing` : "");
334	      }
335	    } catch (e) {
336	      check(`${tag} axe audit ran`, false, String(e).slice(0, 120));
337	    }
338	
339	    await page.close();
340	  }
341	
342	  // ---- REDUCED-MOTION pass: zero GL bytes, content still present ------------
343	  {
344	    const page = await browser.newPage({
345	      viewport: { width: 1440, height: 900 },
346	      reducedMotion: "reduce",
347	    });
348	    const requests = [];
349	    page.on("request", (r) => requests.push(r.url()));
350	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
351	    await sleep(3000);
352	    await page.evaluate(() =>
353	      window.__lenis
354	        ? window.__lenis.scrollTo(document.body.scrollHeight, { immediate: true })
355	        : window.scrollTo(0, document.body.scrollHeight)
356	    );
357	    await sleep(2000);
358	    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
359	    check(
360	      `[${route.name}] reduced-motion: zero GL chunks fetched`,
361	      leaked.length === 0,
362	      leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : ""
363	    );
364	    if (route.mobileStatic) {
365	      const hasText = await page.evaluate(() => document.body.innerText.trim().length > 200);
366	      check(`[${route.name}] reduced-motion: content rendered (not blank)`, hasText);
367	    }
368	    // S03: reduced tier = native scroll (no Lenis), page fully scrollable — the
369	    // scrollTo-bottom above must have actually moved the window.
370	    const rm = await page.evaluate(() => ({
371	      scrolledY: window.scrollY,
372	      noLenis: typeof window.__lenis === "undefined",
373	    }));
374	    check(
375	      `[${route.name}] reduced-motion: native scroll reaches bottom`,
376	      rm.noLenis && rm.scrolledY > 100,
377	      `(lenis=${!rm.noLenis} scrollY=${rm.scrolledY})`
378	    );
379	    // S05: cursor gated OFF under prefers-reduced-motion (native cursor only).
380	    const rmCursor = await page.evaluate(() => !!document.querySelector("[data-magnetic-cursor]"));
381	    check(`[${route.name}] reduced-motion: no custom cursor`, !rmCursor);
382	    await page.close();
383	  }
384	
385	  // ---- MOBILE pass: zero GL bytes, no horizontal overflow, content present --
386	  {
387	    const page = await browser.newPage({ viewport: { width: 390, height: 844 }, hasTouch: true });
388	    const requests = [];
389	    page.on("request", (r) => requests.push(r.url()));
390	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
391	    await sleep(3000);
392	    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
393	    check(
394	      `[${route.name}] mobile: zero GL chunks fetched`,
395	      leaked.length === 0,
396	      leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : ""
397	    );
398	    const m = await page.evaluate(() => ({
399	      overflowX: document.documentElement.scrollWidth <= window.innerWidth + 1,
400	      hasText: document.body.innerText.trim().length > 200,
401	    }));
402	    check(`[${route.name}] mobile: no horizontal overflow`, m.overflowX);
403	    if (route.mobileStatic) check(`[${route.name}] mobile: content present`, m.hasText);
404	
405	    // S05: cursor gated OFF on mobile; hamburger menu opens with all links.
406	    const mobChrome = await page.evaluate(() => ({
407	      cursor: !!document.querySelector("[data-magnetic-cursor]"),
408	      toggle: !!document.querySelector("[data-nav-toggle]"),
409	    }));
410	    check(`[${route.name}] mobile: no custom cursor`, !mobChrome.cursor);
411	    check(`[${route.name}] mobile: nav toggle present`, mobChrome.toggle);
412	    if (mobChrome.toggle) {
413	      await page.click("[data-nav-toggle]");
414	      await sleep(350);
415	      const menu = await page.evaluate(() => {
416	        const links = [...document.querySelectorAll("#mobile-menu a")];
417	        return {
418	          count: links.length,
419	          visible: links.length > 0 && links.every((a) => a.getBoundingClientRect().height > 0),
420	        };
421	      });
422	      check(
423	        `[${route.name}] mobile: menu opens (4 routes + Calendly tappable)`,
424	        menu.count >= 5 && menu.visible,
425	        `(${menu.count} links, visible=${menu.visible})`
426	      );
427	    }
428	    await page.close();
429	  }
430	}
431	
432	// ---- S03 backbone suite: preloader lifecycle + trigger-leak cycle ----------
433	// Runs once (home-anchored); skipped when --route targets another path.
434	if (!onlyRoute || onlyRoute === "/") {
435	  // (a) Preloader first-load lifecycle: veil appears, finishes, unlocks.
436	  {
437	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
438	    const consoleErrors = [];
439	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 200)));
440	    await page.goto(DEV_URL + "/", { waitUntil: "load", timeout: 60000 });
441	
442	    let sawVeil = true;
443	    try {
444	      await page.waitForSelector("[data-preloader]", { timeout: 5000 });
445	    } catch {
446	      sawVeil = false;
447	    }
448	    check("[backbone] preloader veil shows on first load", sawVeil);
449	
450	    let veilGone = true;
451	    try {
452	      await page.waitForSelector("[data-preloader]", { state: "detached", timeout: 10000 });
453	    } catch {
454	      veilGone = false;
455	    }
456	    check("[backbone] preloader completes and unmounts", veilGone);
457	
458	    const post = await page.evaluate(() => ({
459	      done: window.__preloaderDone === true,
460	      unlocked: document.documentElement.style.overflow !== "hidden",
461	      scrollable: document.documentElement.scrollHeight > window.innerHeight,
462	    }));
463	    check("[backbone] preloaderDone fired after veil", post.done);
464	    check("[backbone] scroll unlocked after preloader", post.unlocked && post.scrollable,
465	      `(overflowUnlocked=${post.unlocked} scrollable=${post.scrollable})`);
466	
467	    // (b) Once per session: an in-app nav must NOT re-show it…
468	    await page.click('nav a[href="/work"]');
469	    await sleep(800);
470	    const reshownNav = await page.evaluate(() => !!document.querySelector("[data-preloader]"));
471	    check("[backbone] preloader NOT re-shown on in-app nav", !reshownNav);
472	    // …and neither must a same-session reload (sessionStorage gate).
473	    await page.reload({ waitUntil: "load" });
474	    await sleep(1200);
475	    const reshownReload = await page.evaluate(() => ({
476	      veil: !!document.querySelector("[data-preloader]"),
477	      done: window.__preloaderDone === true,
478	    }));
479	    check("[backbone] preloader NOT re-shown on same-session reload", !reshownReload.veil);
480	    check("[backbone] preloaderDone still fires when session-skipped", reshownReload.done);
481	    check("[backbone] preloader suite: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
482	    await page.close();
483	  }
484	
485	  // (c) ?skippreload bypass: no veil ever, preloaderDone still fires.
486	  {
487	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
488	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
489	    await sleep(1000);
490	    const r = await page.evaluate(() => ({
491	      veil: !!document.querySelector("[data-preloader]"),
492	      done: window.__preloaderDone === true,
493	    }));
494	    check("[backbone] ?skippreload: no preloader node", !r.veil);
495	    check("[backbone] ?skippreload: preloaderDone still fired", r.done);
496	    await page.close();
497	  }
498	
499	  // (d) THE leak assertion (scar #9): 3 full /->work->studio->contact->/ SPA
500	  // cycles; __stCount() must return to the post-load baseline after each.
501	  {
502	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
503	    const pageErrors = [];
504	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
505	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
506	    await sleep(1500);
507	
508	    const baseline = await stCount(page);
509	    check("[backbone] __stCount baseline > 0 (route sentinel alive)", baseline > 0, `(${baseline})`);
510	
511	    const CYCLE = ["/work", "/studio", "/contact", "/"];
512	    const counts = [];
513	    for (let cycle = 1; cycle <= 3; cycle++) {
514	      for (const path of CYCLE) {
515	        await page.click(`nav a[href="${path}"]`);
516	        await sleep(450);
517	      }
518	      await sleep(600); // let the debounced refresh settle
519	      counts.push(await stCount(page));
520	    }
521	    check(
522	      "[backbone] zero trigger leak across 3 route cycles",
523	      counts.every((c) => c === baseline),
524	      `(baseline=${baseline} after cycles=${counts.join(",")})`
525	    );
526	    check("[backbone] leak suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
527	    await page.close();
528	  }
529	
530	  // (e) S05 chrome: nav links actually NAVIGATE (route changes + the new page
531	  // mounts through the transition seam), from both the navbar and the footer.
532	  {
533	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
534	    const pageErrors = [];
535	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 200)));
536	    await page.goto(DEV_URL + "/?skippreload", { waitUntil: "load", timeout: 60000 });
537	    await sleep(1200);
538	
539	    await page.click('header nav a[href="/work"]');
540	    await sleep(900);
541	    const toWork = await page.evaluate(() => ({
542	      path: window.location.pathname,
543	      mounted: !!document.getElementById("case-studies"),
544	    }));
545	    check(
546	      "[chrome] navbar link navigates / -> /work (page mounts in seam)",
547	      toWork.path === "/work" && toWork.mounted,
548	      `(path=${toWork.path} mounted=${toWork.mounted})`
549	    );
550	
551	    await page.click('footer a[href="/studio"]');
552	    await sleep(900);
553	    const toStudio = await page.evaluate(() => ({
554	      path: window.location.pathname,
555	      mounted: !!document.getElementById("team"),
556	    }));
557	    check(
558	      "[chrome] footer link navigates /work -> /studio",
559	      toStudio.path === "/studio" && toStudio.mounted,
560	      `(path=${toStudio.path} mounted=${toStudio.mounted})`
561	    );
562	
563	    // Condense-on-scroll: shell-level trigger flips data-condensed and SURVIVES
564	    // navigation (it lives outside the per-route context — the scar-#9 trap).
565	    const condense = await page.evaluate(async () => {
566	      const header = document.querySelector("header[class*='sticky']") || document.querySelector("header");
567	      if (window.__lenis) window.__lenis.scrollTo(400, { immediate: true });
568	      else window.scrollTo(0, 400);
569	      await new Promise((r) => setTimeout(r, 500));
570	      const condensed = header?.hasAttribute("data-condensed");
571	      if (window.__lenis) window.__lenis.scrollTo(0, { immediate: true });
572	      else window.scrollTo(0, 0);
573	      await new Promise((r) => setTimeout(r, 500));
574	      const expanded = !header?.hasAttribute("data-condensed");
575	      return { condensed, expanded };
576	    });
577	    check(
578	      "[chrome] navbar condenses on scroll + survives navigation",
579	      condense.condensed && condense.expanded,
580	      `(condensed=${condense.condensed} re-expanded=${condense.expanded})`
581	    );
582	    check("[chrome] nav suite: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
583	    await page.close();
584	  }
585	}
586	
587	// ---- S04 lab suite: motion primitive proof bench (/lab, DEV-only) ----------
588	// /lab mounts every v2 primitive once (src/pages/Lab.jsx). Asserted per tier:
589	// desktop = motion tier (strikes fire, pins exist, latches commit), reduced +
590	// mobile = designed static finals (scar #8). The route only exists on the dev
591	// server — the prod build DCEs it out (checked separately via the build grep).
592	const LAB_BLOCKS = [
593	  "split-lines", "ink-reveal", "draft-line", "dimension-mark", "snap-stack",
594	  "axis-rail", "kinetic-marquee", "magnetic-button", "magnetic-cursor",
595	  "count-strike", "scrub-scene", "parallax-layer", "chapter-marker", "section",
596	];
597	const labWalk = async (page, steps = 12, settle = 650) => {
598	  for (let i = 1; i <= steps; i++) {
599	    await page.evaluate((f) => {
600	      const max = document.documentElement.scrollHeight - window.innerHeight;
601	      const y = Math.round(max * f);
602	      if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
603	      else window.scrollTo(0, y);
604	    }, i / steps);
605	    await sleep(settle);
606	  }
607	};
608	if (!onlyRoute || onlyRoute === "/lab") {
609	  const labUrl = DEV_URL + "/lab?skippreload";
610	
611	  // (a) DESKTOP — motion tier: everything mounts, strikes fire, latches commit.
612	  {
613	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
614	    const consoleErrors = [];
615	    const pageErrors = [];
616	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
617	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
618	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
619	    await sleep(2500); // fonts.ready + split/measure + first triggers
620	
621	    const missing = await page.evaluate(
622	      (names) => names.filter((n) => !document.querySelector(`[data-lab="${n}"]`)),
623	      LAB_BLOCKS
624	    );
625	    check(
626	      "[lab] all 14 primitive blocks mount",
627	      missing.length === 0,
628	      missing.length ? `missing: ${missing.join(",")}` : ""
629	    );
630	
631	    const tier = await page.evaluate(() => ({
632	      statics: document.querySelectorAll('[data-lab] [data-static="true"], [data-lab][data-static="true"]').length,
633	      pinSpacers: document.querySelectorAll(".pin-spacer").length,
634	      cursor: !!document.querySelector("[data-magnetic-cursor]"),
635	    }));
636	    check("[lab] desktop: motion tier active (zero static fallbacks)", tier.statics === 0, `(${tier.statics})`);
637	    check("[lab] desktop: pinned scenes mounted (axis-rail + scrub-scene)", tier.pinSpacers >= 2, `(${tier.pinSpacers} pin-spacers)`);
638	    check("[lab] desktop: magnetic cursor mounted", tier.cursor);
639	
640	    await labWalk(page);
641	    await sleep(900);
642	
643	    const settled = await page.evaluate(() => {
644	      const ink = document.querySelector('[data-lab="ink-reveal"] [data-ink-reveal]');
645	      const split = document.querySelector('[data-lab="split-lines"] [data-split-lines]');
646	      const counts = [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim());
647	      const rail = document.querySelector("[data-axis-rail]");
648	      return {
649	        inkRevealed: ink?.getAttribute("data-revealed") === "true",
650	        inkOpacity: ink ? getComputedStyle(ink).opacity : "missing",
651	        splitDone: split?.getAttribute("data-split") === "done",
652	        splitText: (split?.closest('[data-lab="split-lines"]')?.innerText || "")
653	          .replace(/\s+/g, " ")
654	          .includes("Blueprints resolve into built reality"),
655	        counts,
656	        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
657	        railLatched: rail?.getAttribute("data-latched") || "(none)",
658	      };
659	    });
660	    check(
661	      "[lab] InkReveal struck + holds (opacity 1)",
662	      settled.inkRevealed && settled.inkOpacity === "1",
663	      `(revealed=${settled.inkRevealed} opacity=${settled.inkOpacity})`
664	    );
665	    check(
666	      "[lab] SplitLines revealed, text intact",
667	      settled.splitDone && settled.splitText,
668	      `(done=${settled.splitDone} textOk=${settled.splitText})`
669	    );
670	    check("[lab] CountStrike ₹2,41,800 committed", settled.counts.some((t) => t.includes("2,41,800")), `(${settled.counts.join(" | ")})`);
671	    check("[lab] CountStrike 99.3% committed", settled.counts.some((t) => t.includes("99.3")), `(${settled.counts.join(" | ")})`);
672	    check("[lab] ScrubScene progress committed to 1.000", settled.readout === "1.000", `(${settled.readout})`);
673	    check("[lab] AxisRail latched end state (scar #5)", settled.railLatched === "end", `(${settled.railLatched})`);
674	
675	    // Fling commit (scar #5): hard top, then one immediate jump past everything —
676	    // latches must still land the end states, nothing strands mid-scrub.
677	    await page.evaluate(() => (window.__lenis ? window.__lenis.scrollTo(0, { immediate: true }) : window.scrollTo(0, 0)));
678	    await sleep(500);
679	    await page.evaluate(() => {
680	      const max = document.documentElement.scrollHeight - window.innerHeight;
681	      if (window.__lenis) window.__lenis.scrollTo(max, { immediate: true });
682	      else window.scrollTo(0, max);
683	    });
684	    await sleep(1400);
685	    const flung = await page.evaluate(() => ({
686	      readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
687	      railLatched: document.querySelector("[data-axis-rail]")?.getAttribute("data-latched"),
688	    }));
689	    check(
690	      "[lab] fling commits end states (scar #5 latch)",
691	      flung.readout === "1.000" && flung.railLatched === "end",
692	      `(readout=${flung.readout} rail=${flung.railLatched})`
693	    );
694	
695	    // Scar #9: every lab trigger dies on route-leave.
696	    const labCount = await stCount(page);
697	    check("[lab] __stCount > 0 on /lab", labCount > 0, `(${labCount})`);
698	    await page.click('nav a[href="/"]');
699	    await sleep(900);
