701	    check(
702	      "[lab] lab triggers die on route-leave (scar #9)",
703	      homeCount >= 1 && homeCount < labCount,
704	      `(lab=${labCount} home=${homeCount})`
705	    );
706	
707	    check("[lab] desktop: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
708	    check("[lab] desktop: zero page errors", pageErrors.length === 0, pageErrors[0] || "");
709	
710	    // axe (WCAG 2 A+AA) on the bench too — dev-only is no excuse for bad contrast.
711	    try {
712	      await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
713	      await sleep(2000);
714	      await page.addScriptTag({ content: AXE_SOURCE });
715	      const axe = await page.evaluate(async () => {
716	        const res = await window.axe.run(document, {
717	          runOnly: { type: "tag", values: ["wcag2a", "wcag2aa"] },
718	          resultTypes: ["violations"],
719	        });
720	        return res.violations.map((v) => ({ id: v.id, impact: v.impact, nodes: v.nodes.length, help: v.help }));
721	      });
722	      const blocking = axe.filter((v) => v.impact === "critical" || v.impact === "serious");
723	      check(
