727	      );
728	    } catch (e) {
729	      check("[lab] axe audit ran", false, String(e).slice(0, 120));
730	    }
731	    await page.close();
732	  }
733	
734	  // (b) REDUCED-MOTION — designed static finals, no pins, no GL, no cursor.
735	  {
736	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 }, reducedMotion: "reduce" });
737	    const consoleErrors = [];
738	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
739	    const requests = [];
740	    page.on("request", (r) => requests.push(r.url()));
741	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
742	    await sleep(2500);
743	
744	    const r = await page.evaluate((names) => {
745	      const blocksWithStatic = names.filter((n) => {
746	        const w = document.querySelector(`[data-lab="${n}"]`);
747	        return w && (w.matches('[data-static="true"]') || w.querySelector('[data-static="true"]'));
748	      });
749	      const split = document.querySelector('[data-lab="split-lines"]');
750	      const ink = document.querySelector('[data-lab="ink-reveal"] [data-ink-reveal], [data-lab="ink-reveal"] [data-static]');
751	      return {
752	        blocksWithStatic: blocksWithStatic.length,
753	        pinSpacers: document.querySelectorAll(".pin-spacer").length,
754	        cursor: !!document.querySelector("[data-magnetic-cursor]"),
755	        splitText: (split?.innerText || "").replace(/\s+/g, " ").includes("Blueprints resolve into built reality"),
756	        inkVisible: ink ? getComputedStyle(ink).opacity === "1" : false,
757	        counts: [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim()),
758	        readout: document.querySelector("[data-lab-progress]")?.textContent.trim(),
759	        hasText: document.body.innerText.trim().length > 400,
760	      };
761	    }, LAB_BLOCKS);
762	    check("[lab] reduced: static fallbacks rendered (>= 11 blocks)", r.blocksWithStatic >= 11, `(${r.blocksWithStatic})`);
763	    check("[lab] reduced: zero pins", r.pinSpacers === 0, `(${r.pinSpacers})`);
764	    check("[lab] reduced: no custom cursor", !r.cursor);
765	    check("[lab] reduced: SplitLines static text fully readable", r.splitText);
766	    check("[lab] reduced: InkReveal final state visible", r.inkVisible);
767	    check(
768	      "[lab] reduced: CountStrike shows final numbers immediately",
769	      r.counts.some((t) => t.includes("2,41,800")) && r.counts.some((t) => t.includes("99.3")),
770	      `(${r.counts.join(" | ")})`
771	    );
772	    check("[lab] reduced: ScrubScene reports final progress 1.000", r.readout === "1.000", `(${r.readout})`);
773	    check("[lab] reduced: content present (not blank)", r.hasText);
774	    const leaked = requests.filter((u) => GL_CHUNKS.test(u));
775	    check("[lab] reduced: zero GL chunks fetched", leaked.length === 0, leaked[0] ? `leaked: ${leaked[0].split("/").pop()}` : "");
776	    check("[lab] reduced: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
777	    await page.close();
778	  }
779	
780	  // (c) MOBILE 390px — static tier + zero horizontal overflow.
781	  {
782	    const page = await browser.newPage({ viewport: { width: 390, height: 844 }, hasTouch: true });
783	    const consoleErrors = [];
784	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
785	    await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
786	    await sleep(2500);
787	    const m = await page.evaluate((names) => ({
788	      missing: names.filter((n) => !document.querySelector(`[data-lab="${n}"]`)).length,
789	      overflowOk: document.documentElement.scrollWidth <= window.innerWidth + 1,
790	      pinSpacers: document.querySelectorAll(".pin-spacer").length,
791	      cursor: !!document.querySelector("[data-magnetic-cursor]"),
792	      counts: [...document.querySelectorAll("[data-count-strike]")].map((e) => e.textContent.trim()),
793	      hasText: document.body.innerText.trim().length > 400,
794	    }), LAB_BLOCKS);
795	    check("[lab] mobile: all blocks mount", m.missing === 0, `(${m.missing} missing)`);
796	    check("[lab] mobile: no horizontal overflow at 390px", m.overflowOk);
797	    check("[lab] mobile: zero pins", m.pinSpacers === 0, `(${m.pinSpacers})`);
798	    check("[lab] mobile: no custom cursor (coarse pointer)", !m.cursor);
799	    check(
800	      "[lab] mobile: CountStrike final numbers immediate",
801	      m.counts.some((t) => t.includes("2,41,800")),
802	      `(${m.counts.join(" | ")})`
803	    );
804	    check("[lab] mobile: content present", m.hasText);
805	    check("[lab] mobile: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
806	    await page.close();
807	  }
808	}
809	
810	await browser.close();
811	
812	const fails = results.filter((r) => !r.ok);
813	console.log(`\n${results.length - fails.length}/${results.length} checks passed`);
814	if (fails.length) {
815	  console.log("\nFAILURES:");
816	  for (const f of fails) console.log(`  - ${f.name}${f.info ? `  ${f.info}` : ""}`);
817	}
818	process.exit(fails.length ? 1 : 0);
