import { lazy, Suspense } from "react";
import { Routes, Route } from "react-router-dom";
import RootLayout from "./pages/RootLayout.jsx";
import Home from "./pages/Home.jsx";
import Work from "./pages/Work.jsx";
import Studio from "./pages/Studio.jsx";
import Contact from "./pages/Contact.jsx";
import NotFound from "./pages/NotFound.jsx";

// /lab is the S04 dev-only motion-primitive proof bench, DCE'd out of prod.
const Lab = import.meta.env.DEV ? lazy(() => import("./pages/Lab.jsx")) : null;

// 4-route shell (locked IA: / /work /studio /contact) + catch-all. The layout
// route wraps every page in nav + footer. Stubs only this sprint — S03 adds the
// Lenis/ScrollTrigger backbone; S05 the real chrome + page-transition seam; the
// page sprints (S06–S09) compose the real sections. The Outlet stays a plain
// wrapper, never a transformed scroll container (scar #2).
export default function App() {
  return (
    <Routes>
      <Route element={<RootLayout />}>
        <Route path="/" element={<Home />} />
        <Route path="/work" element={<Work />} />
        <Route path="/studio" element={<Studio />} />
        <Route path="/contact" element={<Contact />} />
