/**
 * H2 — CustomsIQ pipeline showpiece SHELL (Home). S06 builds the section +
 * the designed STATIC fallback; S11 builds the GL assemble/disassemble.
 *
 * ── S11 CONTRACT (load-bearing — read before touching) ─────────────────────
 *  - Mount: [data-showpiece="pipeline"] below. Already `position: relative`
 *    (scar #4). The GL canvas attaches as an `absolute inset-0` child of the
 *    mount, layered OVER the fallback.
 *  - Fallback: [data-pipeline-fallback] (direct child) is the COMPLETE static
 *    finished graph — all 5 stages, full agent.trace, every key number, the
 *    knowledge-graph SVG with all nodes lit. THIS is the lite/none/reduced/
 *    mobile design (scar #8 — never a blank). S11 hides it only on the full
 *    GL tier and must keep it rendered (not display:none in the DOM tree
 *    removal sense) for lite tiers.
 *  - Data: everything renders from src/data/pipeline.js (PIPELINE.steps /
 *    PIPELINE.graph). S11 drives the same data — no duplicate content.
 *  - Pin: S06 ships the section TALL and unpinned (no scrub yet). S11 owns
 *    the pin+scrub and MUST register it via useRouteScrollContext().add()
 *    (scar #9) with an onLeave/onLeaveBack latch (scar #5).
 * ────────────────────────────────────────────────────────────────────────────
 *
 * Static design: left = the 5 numbered stage rows (Read → Cite) with their
 * captions; right = knowledge-graph sheet + agent.trace panel carrying the
 * locked numbers (HS 8471.30, BCD 0%, IGST 18%, ₹2,41,800, confidence 0.94,
 * the notification + CAAR ruling). Entrance reveals only — no scroll-scrub.
 */
import { PIPELINE } from "../../data/pipeline.js";
import {
  Section,
  SectionHeader,
  InkReveal,
  DraftLine,
} from "../../components/motion/index.js";

const NODE_R = 15;

function GraphSheet() {
  const { nodes, edges } = PIPELINE.graph;
  const byId = Object.fromEntries(nodes.map((n) => [n.id, n]));
  return (
    <div className="rounded-md border border-line bg-surface-2">
      <div className="flex items-center justify-between border-b border-line px-4 py-2.5">
        <span className="font-mono text-mono-label uppercase text-muted">
          knowledge graph · HS 8471
        </span>
        <span className="font-mono text-mono-label uppercase text-accent">
          all nodes resolved
        </span>
      </div>
      <svg
        viewBox="20 15 380 280"
        className="h-auto w-full"
        role="img"
        aria-label="Knowledge graph: invoice and document nodes resolving through chapters, rulings and rules into HS code 8471.30"
      >
        <g stroke="var(--k-line-2)" strokeWidth="1.5">
          {edges.map(([a, b]) => (
            <line
              key={`${a}-${b}`}
              x1={byId[a].x}
              y1={byId[a].y}
              x2={byId[b].x}
              y2={byId[b].y}
            />
          ))}
        </g>
        {nodes.map((n) => {
          const isHs = n.id === "hs";
          return (
            <g key={n.id}>
              <circle
                cx={n.x}
                cy={n.y}
                r={isHs ? NODE_R + 5 : NODE_R}
                fill={isHs ? "var(--k-accent-soft)" : "var(--k-surface)"}
                stroke={isHs ? "var(--k-accent)" : "var(--k-muted)"}
                strokeWidth={isHs ? 2 : 1}
              />
              <text
                x={n.x}
                y={n.y + (isHs ? NODE_R + 5 : NODE_R) + 13}
                textAnchor="middle"
                fontFamily="JetBrains Mono, ui-monospace, monospace"
                fontSize="11"
                fill={isHs ? "var(--k-ink)" : "var(--k-ink-dim)"}
                fontWeight={isHs ? "600" : "400"}
              >
                {n.t}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

function TracePanel() {
  return (
    <div className="rounded-md border border-line bg-surface-2">
      <div className="flex items-center justify-between border-b border-line px-4 py-2.5">
        <span className="font-mono text-mono-label uppercase text-muted">
          agent.trace
        </span>
        <span className="font-mono text-mono-label uppercase text-muted">
          invoice_8842
        </span>
      </div>
      <div className="space-y-4 px-4 py-4 font-mono text-mono-trace">
        {PIPELINE.steps.map((step, i) => (
          <div key={step.label}>
            <p className="text-muted">
              # {String(i + 1).padStart(2, "0")} {step.label.toLowerCase()}
            </p>
            {step.trace.map(([prefix, text, ok], j) => (
              <p
                key={j}
                className={
                  ok
                    ? "border-l-2 border-accent pl-2 font-medium text-ink"
                    : "text-ink-dim"
                }
              >
                {prefix ? <span className="text-muted">{prefix} </span> : null}
                {text}
              </p>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

export default function PipelineShell() {
  return (
    <Section id="pipeline" bordered>
      <SectionHeader
        eyebrow="CustomsIQ — project demo"
        title="Watch one classification get built."
        lead="A customs agent that reads the shipment, grounds itself in law, reasons in the open, commits a code and cites every source. The finished decision, drawn in full:"
      />

      {/* S11 mount — relative (scar #4); the GL canvas overlays this box. */}
      <div data-showpiece="pipeline" className="relative mt-14">
        <div data-pipeline-fallback="" className="grid gap-10 lg:grid-cols-[2fr_3fr]">
          {/* the 5 stages, engraved */}
          <ol className="self-start">
            {PIPELINE.steps.map((step, i) => (
              <li key={step.label} className="relative border-t border-line">
                <InkReveal from="up" delay={i * 0.08} className="flex gap-5 py-6">
                  <span
                    className={`font-mono text-mono-label uppercase ${
                      step.label === "Classify" ? "text-accent" : "text-muted"
                    }`}
                  >
                    {String(i + 1).padStart(2, "0")}
                  </span>
                  <div>
                    <h3 className="font-display text-title font-semibold text-ink">
                      {step.label}
                    </h3>
                    <p className="mt-2 font-body text-small text-ink-dim">
                      {step.cap[1]}
                    </p>
                  </div>
                </InkReveal>
              </li>
            ))}
            <li aria-hidden="true">
              <DraftLine orient="h" accent />
            </li>
          </ol>

          {/* the sheet: graph + trace */}
          <div className="space-y-6">
            <InkReveal from="right" delay={0.15}>
              <GraphSheet />
            </InkReveal>
            <InkReveal from="right" delay={0.3}>
              <TracePanel />
            </InkReveal>
          </div>
        </div>
      </div>
    </Section>
  );
}

