1	/**
2	 * useRouteScrollContext — the per-route ScrollTrigger lifecycle (scar #9).
3	 *
4	 * EVERY page component (S06–S13) MUST wrap its scroll work in this hook.
5	 * No ad-hoc ScrollTriggers outside a route context — that is how triggers
6	 * leak across navigations and silently break every later pin.
7	 *
8	 * Contract:
9	 *   const { scopeRef, add, refreshSoon } = useRouteScrollContext();
10	 *   - Attach `scopeRef` to the page's root element (a PLAIN block — never a
11	 *     transformed scroll container, scar #2). gsap.context selector text is
12	 *     scoped to it.
13	 *   - Register every tween/trigger via `add(() => { ...gsap/ScrollTrigger... })`.
14	 *     Sections lower in the tree may call `add` before the context exists
15	 *     (child effects run first) — those callbacks are queued and flushed into
16	 *     the context the moment it is created, so ordering is safe.
17	 *   - On route unmount the context `revert()`s: every trigger/tween created
18	 *     inside it is killed BEFORE the next route mounts its own (scar #9).
19	 *     A section that unmounts INDEPENDENTLY of the route (lazy/conditional UI)
20	 *     must manage its own nested gsap.context and revert it in its cleanup.
21	 *
22	 * Scar #1 — NEVER call `self.kill()` synchronously inside a ScrollTrigger
23	 * `onUpdate`/`onToggle`; it corrupts trigger iteration and silently freezes
24	 * every later trigger. Defer instead:
25	 *   onUpdate: (self) => { if (done) gsap.delayedCall(0, () => self.kill()); }
26	 *
27	 * Scar #3 — never call ScrollTrigger.refresh() yourself from a section.
28	 * `refreshSoon()` below is THE one coordinated, debounced refresh channel
29	 * (fonts.ready + preloaderDone + route mounts all funnel through it; S13 calls
30	 * it after the page transition-in).
31	 *
32	 * StrictMode (scar #7): the effect is idempotent — double-invoke creates,
33	 * reverts, recreates; queued section callbacks re-queue on their own re-run.
34	 */
35	import { useCallback, useLayoutEffect, useRef } from "react";
36	import { gsap } from "gsap";
37	import { ScrollTrigger } from "gsap/ScrollTrigger";
38	
39	gsap.registerPlugin(ScrollTrigger);
40	
41	// Dev/QA global: live trigger count — the nav-leak detector verify.mjs cycles.
42	if (typeof window !== "undefined") {
43	  window.__stCount = () => ScrollTrigger.getAll().length;
44	}
45	
46	let refreshCall = null;
47	
48	/**
49	 * The ONE debounced ScrollTrigger.refresh() (scar #3). Safe to call from
50	 * anywhere, any number of times — calls within the debounce window coalesce.
51	 * Runs off gsap.delayedCall (the gsap ticker), never a bare timeout race.
52	 */
53	export function refreshSoon(delaySec = 0.15) {
54	  if (refreshCall) refreshCall.kill();
55	  refreshCall = gsap.delayedCall(delaySec, () => {
56	    refreshCall = null;
57	    ScrollTrigger.refresh();
58	  });
59	}
60	
61	export function useRouteScrollContext() {
62	  const scopeRef = useRef(null);
63	  const ctxRef = useRef(null);
64	  const queueRef = useRef([]);
65	
66	  useLayoutEffect(() => {
67	    const ctx = gsap.context(() => {
68	      // Route sentinel: a zero-cost full-page trigger that (a) proves the
69	      // route context is alive and (b) keeps window.__stCount() >= 1 per
70	      // route so the QA leak assertion measures something real.
71	      ScrollTrigger.create({ id: "route-sentinel", start: 0, end: "max" });
72	    }, scopeRef);
73	    ctxRef.current = ctx;
74	
75	    // Flush section callbacks queued before the context existed (child
76	    // effects run bottom-up, before this page-level effect).
77	    const queued = queueRef.current.splice(0);
78	    for (const fn of queued) ctx.add(fn);
79	
80	    // New route content mounted → coordinated re-measure (scar #3/#9).
81	    refreshSoon();
82	
83	    return () => {
84	      ctxRef.current = null;
85	      queueRef.current = [];
86	      // Kills every trigger/tween registered in this route's context —
87	      // guaranteed to run before the NEXT route's effects (scar #9).
88	      ctx.revert();
89	    };
90	  }, []);
91	
92	  const add = useCallback((fn) => {
93	    if (ctxRef.current) ctxRef.current.add(fn);
94	    else queueRef.current.push(fn);
95	  }, []);
96	
97	  return { scopeRef, add, refreshSoon };
98	}
99

