/**
 * Home (S06) — acts H1–H6 composed from the S04 primitives, all data from
 * src/data/*. Section components live in src/sections/home/*.
 *
 * Owns: #hero #pipeline #industries #services #testimonials #cta and BOTH Home
 * showpiece mounts — [data-showpiece="hero"] (CSS/SVG, S10 fills) and
 * [data-showpiece="pipeline"] (CustomsIQ GL, S11 fills). Work owns "skyline"
 * (S07/S12); testimonials are a HOME act per the BRIEF's IA.
 *
 * Scroll lifecycle: scopeRef wraps the page (plain block, scar #2); every
 * primitive owns its own gsap.context; the ONLY page-level glue is the H6
 * depth-scale scrub below, registered through useRouteScrollContext().add()
 * (scar #9) and skipped entirely on the static tier (scar #8).
 */
import { useLayoutEffect } from "react";
import { gsap } from "gsap";
import { useDocumentHead } from "../lib/useDocumentHead.js";
import { useRouteScrollContext } from "../lib/useRouteScrollContext.js";
import {
  prefersReducedMotion,
  isMobileViewport,
} from "../lib/useReducedMotion.js";
import { SEO } from "../data/seo.js";
import HomeHero from "../sections/home/HomeHero.jsx";
import PipelineShell from "../sections/home/PipelineShell.jsx";
import IndustriesBand from "../sections/home/IndustriesBand.jsx";
import ServicesStack from "../sections/home/ServicesStack.jsx";
import TestimonialsRail from "../sections/home/TestimonialsRail.jsx";
import CtaBanner from "../sections/home/CtaBanner.jsx";

export default function Home() {
  useDocumentHead(SEO["/"]);
  const { scopeRef, add } = useRouteScrollContext();

  // H6 travel vector: the CTA banner scales up in depth as it enters. Linear
  // scrub tracks scroll 1:1 (parallax-class move — settles with the scrub,
  // no latch needed). Mount-time tier decision, like the primitives' gate.
  useLayoutEffect(() => {
    if (prefersReducedMotion() || isMobileViewport()) return;
    add(() => {
      gsap.fromTo(
        "[data-cta-depth]",
        { scale: 0.93, transformOrigin: "50% 80%" },
        {
          scale: 1,
          ease: "none",
          scrollTrigger: {
            trigger: "#cta",
            start: "top bottom",
            end: "top 30%",
            scrub: 0.6,
            invalidateOnRefresh: true,
          },
        }
      );
    });
  }, [add]);

  return (
    <div ref={scopeRef}>
      <HomeHero />
      <PipelineShell />
      <IndustriesBand />
      <ServicesStack />
      <TestimonialsRail />
      <CtaBanner />
    </div>
  );
}

