/**
 * useRouteScrollContext — the per-route ScrollTrigger lifecycle (scar #9).
 *
 * EVERY page component (S06–S13) MUST wrap its scroll work in this hook.
 * No ad-hoc ScrollTriggers outside a route context — that is how triggers
 * leak across navigations and silently break every later pin.
 *
 * Contract:
 *   const { scopeRef, add, refreshSoon } = useRouteScrollContext();
 *   - Attach `scopeRef` to the page's root element (a PLAIN block — never a
 *     transformed scroll container, scar #2). gsap.context selector text is
 *     scoped to it.
 *   - Register every tween/trigger via `add(() => { ...gsap/ScrollTrigger... })`.
 *     Sections lower in the tree may call `add` before the context exists
 *     (child effects run first) — those callbacks are queued and flushed into
 *     the context the moment it is created, so ordering is safe.
 *   - On route unmount the context `revert()`s: every trigger/tween created
 *     inside it is killed BEFORE the next route mounts its own (scar #9).
 *     A section that unmounts INDEPENDENTLY of the route (lazy/conditional UI)
 *     must manage its own nested gsap.context and revert it in its cleanup.
 *
 * Scar #1 — NEVER call `self.kill()` synchronously inside a ScrollTrigger
 * `onUpdate`/`onToggle`; it corrupts trigger iteration and silently freezes
 * every later trigger. Defer instead:
 *   onUpdate: (self) => { if (done) gsap.delayedCall(0, () => self.kill()); }
 *
 * Scar #3 — never call ScrollTrigger.refresh() yourself from a section.
 * `refreshSoon()` below is THE one coordinated, debounced refresh channel
 * (fonts.ready + preloaderDone + route mounts all funnel through it; S13 calls
 * it after the page transition-in).
 *
 * StrictMode (scar #7): the effect is idempotent — double-invoke creates,
 * reverts, recreates; queued section callbacks re-queue on their own re-run.
 */
import { useCallback, useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

// Dev/QA global: live trigger count — the nav-leak detector verify.mjs cycles.
if (typeof window !== "undefined") {
  window.__stCount = () => ScrollTrigger.getAll().length;
}

let refreshCall = null;

/**
 * The ONE debounced ScrollTrigger.refresh() (scar #3). Safe to call from
 * anywhere, any number of times — calls within the debounce window coalesce.
 * Runs off gsap.delayedCall (the gsap ticker), never a bare timeout race.
 */
export function refreshSoon(delaySec = 0.15) {
  if (refreshCall) refreshCall.kill();
  refreshCall = gsap.delayedCall(delaySec, () => {
    refreshCall = null;
    ScrollTrigger.refresh();
  });
}

export function useRouteScrollContext() {
  const scopeRef = useRef(null);
  const ctxRef = useRef(null);
  const queueRef = useRef([]);

  useLayoutEffect(() => {
    const ctx = gsap.context(() => {
      // Route sentinel: a zero-cost full-page trigger that (a) proves the
      // route context is alive and (b) keeps window.__stCount() >= 1 per
      // route so the QA leak assertion measures something real.
      ScrollTrigger.create({ id: "route-sentinel", start: 0, end: "max" });
    }, scopeRef);
    ctxRef.current = ctx;

    // Flush section callbacks queued before the context existed (child
    // effects run bottom-up, before this page-level effect).
    const queued = queueRef.current.splice(0);
    for (const fn of queued) ctx.add(fn);

    // New route content mounted → coordinated re-measure (scar #3/#9).
    refreshSoon();

    return () => {
      ctxRef.current = null;
      queueRef.current = [];
      // Kills every trigger/tween registered in this route's context —
      // guaranteed to run before the NEXT route's effects (scar #9).
      ctx.revert();
    };
  }, []);

  const add = useCallback((fn) => {
    if (ctxRef.current) ctxRef.current.add(fn);
    else queueRef.current.push(fn);
  }, []);

  return { scopeRef, add, refreshSoon };
}

