/**
 * SplitLines — kinetic line-by-line (or word-by-word) text reveal.
 * DIRECTION primitive "SplitLines"; aliases MaskText, SplitTextReveal.
 *
 * The string is rendered as inline-block word <span>s (aria-hidden) inside a
 * root that carries the full text as its accessible name. On the motion tier
 * the words are grouped into visual lines AFTER fonts.ready (scar #3 — measure
 * only once the real metrics exist), each line wrapped in an overflow-hidden
 * mask, and the inner wrappers rise from yPercent:110 / opacity:0 to 0/1 on a
 * one-shot ScrollTrigger. mode="words" masks each word individually instead.
 * The reveal plays once and holds forever.
 *
 * Props
 *   as        string   root tag (default "h2")
 *   children  string   the text — coerced with String(); must be plain text
 *   mode      string   "lines" (group by offsetTop) | "words" (default "lines")
 *   delay     number   seconds before the stagger starts (default 0)
 *   stagger   number   per-line/word stagger seconds (default STAGGER.LINE)
 *   className string   passthrough classes for the root
 *   ...rest            spread onto the root element
 *
 * Gate (scar #8): useMotionStatic() === true ⇒ render the plain string fully
 * visible, no GSAP, data-static="true" data-split="done".
 *
 * Reduced/mobile fallback: identical to the static tier (final readable state).
 *
 * Scars:
 *   #3  await document.fonts.ready before measuring/grouping lines.
 *   #8  static tier = designed final state, zero GSAP, data-static.
 *  #12  the hidden initial gsap.set lives INSIDE the same context as the
 *       trigger, so a load already past the start still reveals (once:true
 *       fires immediately). Word spans are visible by default in markup; only
 *       the motion-tier effect hides the line wrappers.
 *
 * Re-split on width resize (debounced ~200ms, only when width actually
 * changed). If the reveal already played, the re-split renders the FINAL state
 * (no replay) and stamps data-split="done" immediately.
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { EASE, DUR, STAGGER } from "../../lib/motion.js";
import { useMotionStatic } from "./useMotionStatic.js";

gsap.registerPlugin(ScrollTrigger);

export function SplitLines({
  as: Tag = "h2",
  children,
  mode = "lines",
  delay = 0,
  stagger = STAGGER.LINE,
  className,
  ...rest
}) {
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);
  // Survives across resize re-splits within a single mount.
  const playedRef = useRef(false);

  const fullText = String(children ?? "");
  const words = fullText.split(/(\s+)/); // keep whitespace tokens as separators

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    if (!root) return undefined;

    let lastWidth = root.offsetWidth;
    let resizeTimer = null;
    let cancelled = false;

    const ctx = gsap.context(() => {
      // Collect the word spans rendered by React (skip whitespace text nodes).
      const wordSpans = Array.from(
        root.querySelectorAll("[data-split-word]")
      );
      if (!wordSpans.length) {
        root.setAttribute("data-split", "done");
        return;
      }

      // Wrap each word span (or each line group) in an overflow-hidden mask
      // and return the array of inner wrappers we animate.
      const buildLines = () => {
        if (mode === "words") {
          return wordSpans.map((span) => {
            const mask = document.createElement("span");
            mask.style.display = "inline-block";
            mask.style.overflow = "hidden";
            mask.style.verticalAlign = "top";
            const inner = document.createElement("span");
            inner.style.display = "inline-block";
            span.parentNode.insertBefore(mask, span);
            mask.appendChild(inner);
            inner.appendChild(span);
            return inner;
          });
        }
        // mode === "lines": group consecutive words sharing an offsetTop.
        const groups = [];
        let current = null;
        let currentTop = null;
        for (const span of wordSpans) {
          const top = span.offsetTop;
          if (currentTop === null || Math.abs(top - currentTop) > 1) {
            current = [];
            groups.push(current);
            currentTop = top;
          }
          current.push(span);
        }
        return groups.map((group) => {
          const first = group[0];
          const mask = document.createElement("span");
          mask.style.display = "block";
          mask.style.overflow = "hidden";
          const inner = document.createElement("span");
          inner.style.display = "block";
          first.parentNode.insertBefore(mask, first);
          mask.appendChild(inner);
          // Move the whole group (words + interleaved whitespace) into inner.
          let node = first;
          const end = group[group.length - 1];
          while (node) {
            const next = node.nextSibling;
            inner.appendChild(node);
            if (node === end) break;
            node = next;
          }
          return inner;
        });
      };

      // Tear-down created wrappers so a re-split starts from the flat spans.
      const teardown = () => {
        root.querySelectorAll("[data-split-mask]").forEach((mask) => {
          const parent = mask.parentNode;
          while (mask.firstChild) {
            const inner = mask.firstChild;
            while (inner.firstChild) parent.insertBefore(inner.firstChild, mask);
            mask.removeChild(inner);
          }
          parent.removeChild(mask);
        });
      };

      const setup = () => {
        teardown();
        const inners = buildLines();
        inners.forEach((inner) => {
          const mask = inner.parentNode;
          mask.setAttribute("data-split-mask", "");
        });

        if (playedRef.current) {
          // Already revealed once this mount — render final, never replay.
          gsap.set(inners, { yPercent: 0, opacity: 1 });
          root.setAttribute("data-split", "done");
          return;
        }

        gsap.set(inners, { yPercent: 110, opacity: 0 });
        gsap.to(inners, {
          yPercent: 0,
          opacity: 1,
          ease: EASE.PRIMARY,
          duration: DUR.MD,
          stagger,
          delay,
          scrollTrigger: {
            trigger: root,
            start: "top 85%",
            once: true,
          },
          onComplete: () => {
            playedRef.current = true;
            root.setAttribute("data-split", "done");
          },
        });
      };

      const onResize = () => {
        if (cancelled) return;
        const w = root.offsetWidth;
        if (w === lastWidth) return;
        lastWidth = w;
        if (resizeTimer) clearTimeout(resizeTimer);
        resizeTimer = setTimeout(() => {
          if (cancelled) return;
          setup();
          ScrollTrigger.refresh();
        }, 200);
      };

      document.fonts.ready.then(() => {
        if (cancelled) return;
        setup();
        ScrollTrigger.refresh();
      });

      window.addEventListener("resize", onResize);

      // Cleanup registered on the context so revert() runs it (StrictMode-safe).
      return () => {
        cancelled = true;
        if (resizeTimer) clearTimeout(resizeTimer);
        window.removeEventListener("resize", onResize);
        teardown();
      };
    }, rootRef);

    return () => ctx.revert();
    // mode/stagger/delay are stable per design; re-run if they change.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStatic, mode, stagger, delay, fullText]);

  if (isStatic) {
    return (
      <Tag
        ref={rootRef}
        className={className}
        data-split-lines=""
        data-static="true"
        data-split="done"
        {...rest}
      >
        {fullText}
      </Tag>
    );
  }

  return (
    <Tag
      ref={rootRef}
      className={className}
      aria-label={fullText}
      data-split-lines=""
      {...rest}
    >
      {words.map((tok, i) =>
        /\s+/.test(tok) ? (
          // Preserve whitespace as a real text node between word spans.
          tok
        ) : (
          <span
            key={i}
            data-split-word=""
            aria-hidden="true"
            style={{ display: "inline-block" }}
          >
            {tok}
          </span>
        )
      )}
    </Tag>
  );
}

export const MaskText = SplitLines;
export const SplitTextReveal = SplitLines;

export default SplitLines;

