export const meta = {
  name: 'sprint-06-audit',
  description: 'Fresh-eyes visual audit + adversarial scar review for Sprint 06 (Home)',
  phases: [{ title: 'Audit' }],
}

const VERDICT = {
  type: 'object',
  properties: {
    verdict: { type: 'string', enum: ['SHIP', 'FIX'] },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          frame: { type: 'string' },
          severity: { type: 'string', enum: ['blocking', 'minor'] },
          finding: { type: 'string' },
        },
        required: ['frame', 'severity', 'finding'],
      },
    },
  },
  required: ['verdict', 'findings'],
}

phase('Audit')
const [visual, scars] = await parallel([
  () => agent(`You are a FRESH-EYES visual auditor for a portfolio-grade marketing site rebuild. You have NO knowledge of how it was built and must judge only what you see.

Open and LOOK AT every one of these screenshots (use the Read tool on each PNG):
- ALL files matching /tmp/shots/sprint-06/home-*.png (desktop + mobile + preloader frames)
- ALL files in /tmp/shots-dense/home/ (dense desktop scroll walk)

Also read the binding art direction: plans/design/DIRECTION.md and plans/design/TOKENS.md (repo root: /Users/prynq/Desktop/kartar/sachmeetsb.github.io).

Judge every frame against this checklist:
1. READABILITY — all text legible at rendered size; nothing cut off, overlapped, or badly wrapped; sane line lengths.
2. CONTRAST & HIERARCHY — foreground/background separation obvious; ONE clear focal point per viewport; type scale reads eyebrow -> heading -> body.
3. SPACING RHYTHM — consistent section padding; nothing crammed or orphaned; the grid holds.
4. MOTION END-STATES — nothing stuck mid-animation, half-revealed, or below opacity 1 in SETTLED frames. NOTE: frames captured at 25%/50%/75% scroll may legitimately catch a scrubbed horizontal filmstrip or marquee MID-TRAVEL — judge whether it reads as deliberate motion vs broken; top/bottom frames must be fully settled.
5. DIRECTION FIDELITY — frames must look like DIRECTION.md's "Blueprint -> Built" route: graphite ground, warm-bone ink, ONE blueprint-blue accent <=10% of frame, drafting-grid/dimension-mark vocabulary, Clash Display headings — NOT generic dark-SaaS (no glow orbs, glassmorphism, particle fields) and NOT the old saffron/indigo brand.
6. MOBILE DIGNITY — mobile frames are a designed experience, not a squeezed desktop.

Return verdict SHIP only if there are zero blocking findings. Every finding: frame filename, severity (blocking = must fix before ship; minor = cosmetic), and a concrete description with WHERE in the frame.`, { label: 'visual-auditor', schema: VERDICT }),

  () => agent(`You are an adversarial code reviewer enforcing motion-engineering rules ("the 10 scars") on Sprint 06 of a GSAP/Lenis/React site. Repo: /Users/prynq/Desktop/kartar/sachmeetsb.github.io. Review the UNCOMMITTED working-tree changes: run \`git status --porcelain\` and \`git diff\` and read the new files in src/sections/home/ plus src/pages/Home.jsx, and the edits to src/components/motion/SplitLines.jsx, src/lib/useRouteScrollContext.js, scripts/qa/verify.mjs.

Try hard to FIND VIOLATIONS of these rules (read plans/PROTOCOL.md section 2 for the canonical text):
#1 no synchronous self.kill() inside ScrollTrigger onUpdate/onToggle. #2 Lenis scrolls the real window; no transformed scroll containers. #3 ONE coordinated debounced refresh (no scattered ScrollTrigger.refresh() in sections — primitives' own internal refreshes predate this sprint and are out of scope). #4 position:relative on sections hosting absolute inset-0 overlays. #5 scrub latches commit end states. #6 scoped CSS, no global injected styles fighting Tailwind. #7 StrictMode-idempotent effects, gsap.context + revert. #8 mobile<=768 + prefers-reduced-motion render designed static finals (no pins, no horizontal scroll, no blanks). #9 per-route gsap.context; triggers die before next route mounts. #10 no GL on this sprint, no bare rAF loops, no per-frame allocations or getBoundingClientRect.

Also check: all content imported from src/data/* (no hand-typed locked facts), easing only from src/lib/motion.js, no new dependencies, no forbidden colors (#F2A93B #2D1B69 #4A2F9A #00BFA5 #FF5E0E).

Report each violation as a finding with frame=file:line, severity blocking|minor. Verdict SHIP if no blocking violations. Be adversarial but truthful — do not invent violations where the code is compliant.`, { label: 'scar-reviewer', schema: VERDICT }),
])

return { visual, scars }

